try:
    from PIL import Image, ImageDraw, ImageFont
    PIL_AVAILABLE = True
    # Compatibility for older Pillow versions
    if not hasattr(Image, "Resampling"):
        Image.Resampling = Image
    if not hasattr(Image, "LANCZOS"):
        Image.LANCZOS = getattr(Image, "ANTIALIAS", 3)
    if not hasattr(Image, "BICUBIC"):
        Image.BICUBIC = 2
except ImportError:
    PIL_AVAILABLE = False
    Image = ImageDraw = ImageFont = None
    if sys.warnoptions:
        import warnings
        warnings.warn("Pillow not installed. Use: pip install Pillow", UserWarning)


class ImageProcessor:
    """Image processing utilities for display optimization"""
    
    @staticmethod
    def load_image(path: str, width: int = DISPLAY_WIDTH, height: int = DISPLAY_HEIGHT) -> 'Image.Image':
        """Load and resize image for display"""
        if not PIL_AVAILABLE:
            raise RuntimeError("Pillow is required for image processing")
        
        img = Image.open(path).convert('RGBA')
        
        # Resize with aspect ratio preservation
        img.thumbnail((width, height), Image.Resampling.LANCZOS)
        
        # Center on black background (fully opaque)
        final = Image.new('RGBA', (width, height), (0, 0, 0, 255))
        offset = ((width - img.width) // 2, (height - img.height) // 2)
        final.paste(img, offset)
        
        return final
    
    @staticmethod
    def to_bgr_bytes(img: 'Image.Image') -> bytes:
        """Convert PIL Image to BMP BGR byte format"""
        width, height = img.size
        
        # Calculate row size with 4-byte alignment
        row_size = (width * 3 + 3) & ~3
        padding = row_size - (width * 3)
        
        # Generate pixel data (BGR, bottom-up)
        pixel_data = bytearray()
        for y in range(height - 1, -1, -1):
            for x in range(width):
                r, g, b = img.getpixel((x, y))
                pixel_data.extend([b, g, r])
            pixel_data.extend([0] * padding)
        
        return bytes(pixel_data)
    
    @staticmethod
    def create_bmp(img: 'Image.Image') -> bytes:
        """Create BMP file from PIL Image"""
        import struct
        width, height = img.size
        
        row_size = (width * 3 + 3) & ~3
        pixel_data_size = row_size * height
        file_size = 54 + pixel_data_size
        
        # BMP Header
        bmp_header = struct.pack('<2sIHHI',
            b'BM',
            file_size,
            0, 0,
            54
        )
        
        # DIB Header
        dib_header = struct.pack('<IiiHHIIiiII',
            40,
            width,
            height,
            1,
            24,
            0,
            pixel_data_size,
            2835, 2835,
            0, 0
        )
        
        pixel_data = ImageProcessor.to_bgr_bytes(img)
        return bmp_header + dib_header + pixel_data

    @staticmethod
    def create_jpeg(img: 'Image.Image', quality: int = 90) -> bytes:
        """Create JPEG file bytes from PIL Image"""
        buf = io.BytesIO()
        img.save(buf, format='JPEG', quality=quality)
        return buf.getvalue()

    @staticmethod
    def create_png(img: 'Image.Image') -> bytes:
        """Create PNG file bytes from PIL Image"""
        buf = io.BytesIO()
        img.save(buf, format='PNG')
        return buf.getvalue()

    @staticmethod
    def create_gif(img: 'Image.Image') -> bytes:
        """Create GIF file bytes from PIL Image"""
        buf = io.BytesIO()
        # Convert to P mode (palette) for GIF
        if img.mode != 'P':
            img = img.convert('P', palette=Image.ADAPTIVE, colors=256)
        img.save(buf, format='GIF')
        return buf.getvalue()

    @staticmethod
    def encode(img: 'Image.Image', fmt: str = 'png') -> tuple:
        """Encode image as RGBA PNG with .osd timestamp filename (matching CPS protocol)."""
        ts = datetime.now().strftime("%Y-%m-%d_%H-%M-%S-") + str(int(datetime.now().microsecond / 1000))
        filename = f"{ts}.osd"

        if img.mode != 'RGBA':
            img = img.convert('RGBA')

        png_data = ImageProcessor.create_png(img)
        return png_data, filename

    @staticmethod
    def create_test_pattern(pattern: str, width: int = DISPLAY_WIDTH, height: int = DISPLAY_HEIGHT) -> 'Image.Image':
        """Generate test patterns"""
        img = Image.new('RGBA', (width, height), (0, 0, 0, 255))
        draw = ImageDraw.Draw(img)
        
        if pattern == 'blue':
            draw.rectangle([0, 0, width, height], fill=(0, 0, 255, 255))
        elif pattern == 'red':
            draw.rectangle([0, 0, width, height], fill=(255, 0, 0, 255))
        elif pattern == 'green':
            draw.rectangle([0, 0, width, height], fill=(0, 255, 0, 255))
        elif pattern == 'white':
            draw.rectangle([0, 0, width, height], fill=(255, 255, 255, 255))
        elif pattern == 'black':
            draw.rectangle([0, 0, width, height], fill=(0, 0, 0, 255))
        elif pattern == 'gradient':
            for y in range(height):
                r = int(255 * y / height)
                g = int(255 * (1 - y / height))
                b = int(128)
                draw.line([(0, y), (width, y)], fill=(r, g, b))
        elif pattern == 'grid':
            draw.rectangle([0, 0, width, height], fill=(0, 0, 0))
            for i in range(0, width, 40):
                draw.line([(i, 0), (i, height)], fill=(255, 255, 255))
            for i in range(0, height, 40):
                draw.line([(0, i), (width, i)], fill=(255, 255, 255))
        elif pattern == 'colors':
            colors = [(255,0,0), (0,255,0), (0,0,255), (255,255,0), (255,0,255), (0,255,255)]
            cw = width // 3
            ch = height // 2
            for i, color in enumerate(colors):
                x = (i % 3) * cw
                y = (i // 3) * ch
                draw.rectangle([x, y, x+cw, y+ch], fill=color)
        
        return img
    
    @staticmethod
    def create_system_info(width: int = DISPLAY_WIDTH, height: int = DISPLAY_HEIGHT) -> 'Image.Image':
        """Create system info display"""
        img = Image.new('RGBA', (width, height), (20, 20, 40, 255))
        draw = ImageDraw.Draw(img)
        
        # Load system fonts
        from .utils import load_system_fonts
        fonts = load_system_fonts([32, 20, 16])
        font_large, font_medium, font_small = fonts[0], fonts[1], fonts[2]
        
        # Header
        draw.text((20, 20), "PCCooler GT360", fill=(100, 150, 255), font=font_large)
        draw.text((20, 60), f"Display: {width}x{height}", fill=(200, 200, 200), font=font_medium)
        
        # Try to get system stats
        try:
            import psutil
            cpu = psutil.cpu_percent()
            mem = psutil.virtual_memory()
            temp = psutil.sensors_temperatures() if hasattr(psutil, 'sensors_temperatures') else {}
            
            y = 120
            draw.text((20, y), f"CPU: {cpu:.1f}%", fill=(100, 255, 100), font=font_medium)
            y += 40
            draw.text((20, y), f"RAM: {mem.percent:.1f}%", fill=(255, 200, 100), font=font_medium)
            y += 40
            
            if temp:
                for name, temps in list(temp.items())[:2]:
                    if temps:
                        t = temps[0].current
                        draw.text((20, y), f"{name}: {t:.1f}°C", fill=(255, 100, 100), font=font_small)
                        y += 30
        except ImportError:
            draw.text((20, 120), "Install psutil for stats:", fill=(255, 200, 100), font=font_medium)
            draw.text((20, 160), "pip install psutil", fill=(200, 200, 200), font=font_small)
        
        # Footer
        draw.text((20, height - 40), datetime.now().strftime("%Y-%m-%d %H:%M:%S"), 
                  fill=(150, 150, 150), font=font_small)
        
        return img


class ScreensaverGenerator:
    """Generates animated screensaver frames for continuous upload to the display.

    Supported modes: 'mystify', 'starfield', 'bounce'.
    Call next_frame() repeatedly to get successive PIL Image frames.
    """

    MODES = ("mystify", "starfield", "bounce", "pipes", "catpipes")

    def __init__(self, mode: str, width: int = 640, height: int = 480):
        if not PIL_AVAILABLE:
            raise RuntimeError("Pillow is required for screensaver generation")
        self.mode = mode.lower()
        self.width = width
        self.height = height
        self._frame = 0
        self._state = {}
        self._init_state()

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def next_frame(self) -> 'Image.Image':
        """Return the next animated frame as a PIL RGBA Image."""
        if self.mode == "mystify":
            img = self._mystify_frame()
        elif self.mode == "starfield":
            img = self._starfield_frame()
        elif self.mode == "bounce":
            img = self._bounce_frame()
        elif self.mode == "pipes":
            img = self._pipes_frame()
        elif self.mode == "catpipes":
            img = self._catpipes_frame()
        else:
            img = Image.new("RGBA", (self.width, self.height), (0, 0, 0, 255))
        self._frame += 1
        return img

    # ------------------------------------------------------------------
    # Initialisation helpers
    # ------------------------------------------------------------------

    def _init_state(self):
        import random, math
        rng = random.Random(42)
        w, h = self.width, self.height

        if self.mode == "mystify":
            # 2 polygons, each with 4 vertices + velocity (no history list needed)
            polygons = []
            for _ in range(2):
                verts = [(rng.randint(0, w), rng.randint(0, h)) for _ in range(4)]
                vels = [(rng.uniform(-3, 3) or 1.5, rng.uniform(-3, 3) or 1.5) for _ in range(4)]
                polygons.append({"verts": verts, "vels": vels})
            self._state["polygons"] = polygons
            # Persistent canvas: draw on it each frame, fade with semi-transparent overlay
            self._state["canvas"] = Image.new("RGBA", (w, h), (0, 0, 0, 255))
            # Pre-allocated fade overlay (semi-transparent black)
            self._state["fade"] = Image.new("RGBA", (w, h), (0, 0, 0, 210))

        elif self.mode == "starfield":
            n = 200
            # Store as parallel arrays for faster access
            self._state["sx"] = [rng.uniform(-1.0, 1.0) for _ in range(n)]
            self._state["sy"] = [rng.uniform(-1.0, 1.0) for _ in range(n)]
            self._state["sz"] = [rng.uniform(0.1, 1.0)  for _ in range(n)]
            self._state["sp"] = [rng.uniform(0.01, 0.025) for _ in range(n)]
            self._state["n"]  = n
            # Persistent canvas with fade overlay
            self._state["canvas"] = Image.new("RGBA", (w, h), (0, 0, 0, 255))
            self._state["fade"]   = Image.new("RGBA", (w, h), (0, 0, 0, 210))

        elif self.mode in ("pipes", "catpipes"):
            # Grid cell size for 3D pipe segments
            cell = max(16, min(self.width, self.height) // 20)
            self._state["cell"] = cell
            self._state["canvas"] = Image.new("RGBA", (self.width, self.height), (0, 0, 0, 255))
            self._state["pipes"] = []      # list of active pipe dicts
            self._state["reset_after"] = (self.width // cell) * (self.height // cell) * 2
            self._state["steps"] = 0
            self._pipes_add_pipe(rng)

            if self.mode == "catpipes":
                # Also initialise the bouncing cat
                import io
                raw = base64.b64decode(BUILTIN_IMAGE_B64)
                sprite = Image.open(io.BytesIO(raw)).convert("RGBA")
                target_w = max(40, int(self.width * 0.275))
                ratio = target_w / sprite.width
                target_h = int(sprite.height * ratio)
                sprite = sprite.resize((target_w, target_h), Image.Resampling.LANCZOS)
                self._state["sprite"] = sprite
                self._state["bx"] = float(rng.randint(0, max(1, self.width - target_w)))
                self._state["by"] = float(rng.randint(0, max(1, self.height - target_h)))
                speed = max(2.0, min(self.width, self.height) * 0.007)
                self._state["bvx"] = rng.choice([-1, 1]) * speed
                self._state["bvy"] = rng.choice([-1, 1]) * speed

        elif self.mode == "bounce":
            import io
            raw = base64.b64decode(BUILTIN_IMAGE_B64)
            sprite = Image.open(io.BytesIO(raw)).convert("RGBA")
            target_w = max(40, int(w * 0.275))
            ratio = target_w / sprite.width
            target_h = int(sprite.height * ratio)
            sprite = sprite.resize((target_w, target_h), Image.Resampling.LANCZOS)
            self._state["sprite"] = sprite
            self._state["x"] = float(rng.randint(0, max(1, w - target_w)))
            self._state["y"] = float(rng.randint(0, max(1, h - target_h)))
            speed = max(2.0, min(w, h) * 0.007)
            self._state["vx"] = rng.choice([-1, 1]) * speed
            self._state["vy"] = rng.choice([-1, 1]) * speed
            # Pre-allocated black background — copy() is faster than Image.new() each frame
            self._state["bg"] = Image.new("RGBA", (w, h), (0, 0, 0, 255))

    # ------------------------------------------------------------------
    # Mystify
    # ------------------------------------------------------------------

    def _mystify_frame(self) -> 'Image.Image':
        import colorsys
        w, h = self.width, self.height
        polygons = self._state["polygons"]

        # Fade persistent canvas by compositing a semi-transparent black overlay
        canvas = Image.alpha_composite(self._state["canvas"], self._state["fade"])

        draw = ImageDraw.Draw(canvas)
        hue_offset = (self._frame * 0.003)

        for p_idx, poly in enumerate(polygons):
            verts, vels = poly["verts"], poly["vels"]
            new_verts, new_vels = [], []
            for (x, y), (vx, vy) in zip(verts, vels):
                x += vx
                y += vy
                if x <= 0 or x >= w:
                    vx = -vx
                    x = max(0.0, min(float(w), x))
                if y <= 0 or y >= h:
                    vy = -vy
                    y = max(0.0, min(float(h), y))
                new_verts.append((x, y))
                new_vels.append((vx, vy))
            poly["verts"] = new_verts
            poly["vels"]  = new_vels

            hue = (hue_offset + p_idx * 0.5) % 1.0
            r, g, b = colorsys.hsv_to_rgb(hue, 1.0, 1.0)
            color = (int(r * 255), int(g * 255), int(b * 255), 255)
            pts = [(int(x), int(y)) for x, y in new_verts]
            for j in range(len(pts)):
                draw.line([pts[j], pts[(j + 1) % len(pts)]], fill=color, width=2)

        self._state["canvas"] = canvas
        return canvas

    # ------------------------------------------------------------------
    # Starfield
    # ------------------------------------------------------------------

    def _starfield_frame(self) -> 'Image.Image':
        import random
        s = self._state
        cx, cy = self.width / 2, self.height / 2
        scale = max(self.width, self.height) * 0.6
        W, H = self.width, self.height
        sx_arr, sy_arr, sz_arr, sp_arr = s["sx"], s["sy"], s["sz"], s["sp"]
        n = s["n"]
        _rng = random.random  # local binding avoids repeated global lookup

        canvas = Image.alpha_composite(s["canvas"], s["fade"])
        draw = ImageDraw.Draw(canvas)

        for i in range(n):
            sz_arr[i] -= sp_arr[i]
            if sz_arr[i] <= 0:
                sx_arr[i] = _rng() * 2 - 1
                sy_arr[i] = _rng() * 2 - 1
                sz_arr[i] = 1.0
                sp_arr[i] = _rng() * 0.015 + 0.01

            z = sz_arr[i]
            px = int(cx + sx_arr[i] / z * scale)
            py = int(cy + sy_arr[i] / z * scale)

            if 0 <= px < W and 0 <= py < H:
                brightness = int(255 * (1.0 - z))
                size = int((1.0 - z) * 3)
                color = (brightness, brightness, brightness, 255)
                if size <= 0:
                    draw.point((px, py), fill=color)
                else:
                    draw.ellipse([px - size, py - size, px + size, py + size], fill=color)

        s["canvas"] = canvas
        return canvas

    # ------------------------------------------------------------------
    # Bounce (DVD-logo style with embedded cat image)
    # ------------------------------------------------------------------

    def _bounce_frame(self) -> 'Image.Image':
        s = self._state
        img = s["bg"].copy()  # fast memcpy of pre-allocated black background
        sprite: 'Image.Image' = s["sprite"]
        sw, sh = sprite.size

        s["x"] += s["vx"]
        s["y"] += s["vy"]

        bounced = False
        if s["x"] <= 0:
            s["x"] = 0.0
            s["vx"] = abs(s["vx"])
            bounced = True
        elif s["x"] + sw >= self.width:
            s["x"] = float(self.width - sw)
            s["vx"] = -abs(s["vx"])
            bounced = True
        if s["y"] <= 0:
            s["y"] = 0.0
            s["vy"] = abs(s["vy"])
            bounced = True
        elif s["y"] + sh >= self.height:
            s["y"] = float(self.height - sh)
            s["vy"] = -abs(s["vy"])
            bounced = True

        # On bounce, shift hue of sprite for classic DVD effect
        if bounced:
            import colorsys, random
            hue = random.random()
            r, g, b = colorsys.hsv_to_rgb(hue, 0.6, 1.0)
            tint = Image.new("RGBA", sprite.size, (int(r * 255), int(g * 255), int(b * 255), 120))
            tinted = Image.alpha_composite(sprite, tint)
            s["sprite"] = tinted

        img.paste(s["sprite"], (int(s["x"]), int(s["y"])), mask=s["sprite"])
        return img

    # ------------------------------------------------------------------
    # Pipes (3-D Windows XP style)
    # ------------------------------------------------------------------

    # Pipe directions as (dx_grid, dy_grid) grid-cell deltas
    _PIPE_DIRS = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    # Classic XP bright pipe colours
    _PIPE_COLORS = [
        (255, 0,   0,   255),  # red
        (0,   200, 0,   255),  # green
        (0,   100, 255, 255),  # blue
        (255, 200, 0,   255),  # yellow
        (200, 0,   200, 255),  # magenta
        (0,   220, 220, 255),  # cyan
        (255, 130, 0,   255),  # orange
        (200, 200, 200, 255),  # silver
    ]

    def _pipes_add_pipe(self, rng=None):
        import random
        if rng is None:
            rng = random.Random()
        cell = self._state["cell"]
        cols = self.width  // cell
        rows = self.height // cell
        gx = rng.randint(0, cols - 1)
        gy = rng.randint(0, rows - 1)
        color = rng.choice(self._PIPE_COLORS)
        dx, dy = rng.choice(self._PIPE_DIRS)
        self._state["pipes"].append({
            "gx": gx, "gy": gy,
            "dx": dx, "dy": dy,
            "color": color,
        })

    def _pipes_frame(self) -> 'Image.Image':
        import random
        s = self._state
        cell = s["cell"]
        canvas: 'Image.Image' = s["canvas"]
        draw = ImageDraw.Draw(canvas)
        cols = self.width  // cell
        rows = self.height // cell
        rng = random.Random()

        # Advance every active pipe by one segment per frame
        for pipe in s["pipes"]:
            gx, gy = pipe["gx"], pipe["gy"]
            dx, dy = pipe["dx"], pipe["dy"]
            color   = pipe["color"]

            # Pixel centres of current and next cell
            x0 = gx * cell + cell // 2
            y0 = gy * cell + cell // 2
            ngx = gx + dx
            ngy = gy + dy

            # Wrap around edges
            ngx = ngx % cols
            ngy = ngy % rows
            x1 = ngx * cell + cell // 2
            y1 = ngy * cell + cell // 2

            # Draw pipe segment
            hw = max(2, cell // 4)   # half-width of pipe tube
            draw.line([(x0, y0), (x1, y1)], fill=color, width=hw * 2)

            # Draw ball joint at the junction point
            r = hw + 1
            draw.ellipse([x1 - r, y1 - r, x1 + r, y1 + r], fill=color)

            # Randomly turn or continue
            if rng.random() < 0.25:
                pipe["dx"], pipe["dy"] = rng.choice(self._PIPE_DIRS)
            pipe["gx"] = ngx
            pipe["gy"] = ngy

        # Occasionally spawn a new pipe (up to 6 simultaneous)
        if len(s["pipes"]) < 6 and rng.random() < 0.03:
            self._pipes_add_pipe(rng)

        s["steps"] += 1
        # Periodically clear the canvas so it never gets fully opaque
        if s["steps"] >= s["reset_after"]:
            s["canvas"] = Image.new("RGBA", (self.width, self.height), (0, 0, 0, 255))
            s["pipes"] = []
            s["steps"] = 0
            self._pipes_add_pipe(rng)

        return canvas.copy()

    # ------------------------------------------------------------------
    # Cat + Pipes
    # ------------------------------------------------------------------

    def _catpipes_frame(self) -> 'Image.Image':
        import random, colorsys
        # Draw pipes onto the persistent canvas
        pipes_frame = self._pipes_frame()  # updates canvas in-place and returns a copy

        s = self._state
        sprite: 'Image.Image' = s["sprite"]
        sw, sh = sprite.size

        # Move the cat
        s["bx"] += s["bvx"]
        s["by"] += s["bvy"]

        bounced = False
        if s["bx"] <= 0:
            s["bx"] = 0.0
            s["bvx"] = abs(s["bvx"])
            bounced = True
        elif s["bx"] + sw >= self.width:
            s["bx"] = float(self.width - sw)
            s["bvx"] = -abs(s["bvx"])
            bounced = True
        if s["by"] <= 0:
            s["by"] = 0.0
            s["bvy"] = abs(s["bvy"])
            bounced = True
        elif s["by"] + sh >= self.height:
            s["by"] = float(self.height - sh)
            s["bvy"] = -abs(s["bvy"])
            bounced = True

        if bounced:
            rng = random.Random()
            hue = rng.random()
            r, g, b = colorsys.hsv_to_rgb(hue, 0.6, 1.0)
            tint = Image.new("RGBA", sprite.size, (int(r * 255), int(g * 255), int(b * 255), 100))
            tinted = Image.alpha_composite(sprite, tint)
            s["sprite"] = tinted

        # Composite cat on top of the pipes frame
        pipes_frame.paste(s["sprite"], (int(s["bx"]), int(s["by"])), mask=s["sprite"])
        return pipes_frame
